member.example:
Bind the AudioSource panStereo property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourcePanStereoBinder _panStereo;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _panStereo;
    }


Bind the AudioSource panStereo property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourcePanStereoBinder PanStereo =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _panStereo;
    }

Switch the AudioSource panStereo between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourcePanStereoSwitcherBinder _isPanLeft;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isPanLeft;
    }


Switch the AudioSource panStereo between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private float _panLeft;
        
        [SerializeField]
        private float _panRight;
        
        private AudioSourcePanStereoSwitcherBinder IsPanLeft => new(
            _audioSource, _panLeft, _panRight);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isPanLeft;
    }
